import React, { useEffect, useContext, useState } from 'react'
import { Footer } from './Footer'
import { Link } from "react-router-dom";
import { Navbar } from './Navbar';
import { CartBlock } from './CartBlock';
import  ImageSlider  from "./ImageSlider";
import CartContext from './context/CartContext';
import { useHistory, useLocation } from 'react-router';
import  {CheckBox}  from './CheckBox';
import axios from 'axios'
export const CartPage = (props) => {
    const { deletecart } = useContext(CartContext);
    const context = useContext(CartContext)
    const { getcart, carts } = context;
    const [Total, setTotal] = useState(0)
    const [Products, setProducts] = useState([])
    const [PostSize, setPostSize] = useState(0)
    const [Deli, setDeli] = useState({Category: []})

      useEffect(() => {
        getProducts();
      }, [])

    let history = useHistory();
    
    const calculateTotal = ()=>{
        let total = 0;
        carts.map((cart)=>{
            {
                Products.filter((product) => product._id === cart.id).map((product)=>{
                    total += parseInt(product.price , 10) * cart.quantity
                }
                )
            }
        })
        setTotal(total)
    }
    useEffect(() => {
        if (localStorage.getItem('token')) {
            calculateTotal();
            getcart()
        }
        else {
            history.push("/login")
        }
    }, [])

    const url = "http://localhost:5000/api/product/getProducts"
    const getProducts = (variables) => {
        axios.post(url, variables)
            .then(response => {
                if (response.data.success) {
                    setProducts(response.data.products)
                    setPostSize(response.data.postSize)
                    console.log(response.data.products)
                }
                else {
                    alert("failed to fetch product data")
                }
            })
    }
    const showDeliResults = (deli) => {
        const variables = {
            deli: deli
        }
        getProducts(variables);
    }
    const handledelivery = (deli, delicat) => {
        console.log(deli)
        const newDeli = { ...Deli }
        newDeli[delicat] = deli

        showDeliResults(newDeli)

        setDeli(newDeli)
    }

    
    return (
        <>
            <Navbar />
            <div className="cart-area pt-90 pb-90">
                <div className="container">
                    <div className="row justify-content-center">

                        <div className="col-xl-7">
                            <div className="cart-wrapper">
                                <div className="table-responsive">
                                    <table className="table mb-0">
                                        <thead>
                                            <tr>
                                                <th className="product-thumbnail"></th>
                                                <th className="product-name">Product</th>
                                                <th className="product-price">Price</th>
                                                <th className="product-quantity">QUANTITY</th>
                                                <th className="product-subtotal">SUBTOTAL</th>
                                                <th className="product-delete"></th>
                                            </tr>
                                        </thead>
                                        {
                                            carts.map((cart) => {
                                                return <tbody>
                                                {Products.filter((product) => product._id === cart.id).map(
                                                  (product) => (
                                                    <tr>
                                                      <td className="product-thumbnail">
                                                        <ImageSlider images={product.image} />
                                                      </td>
                                                      <td className="product-name">
                                                        <h4> <Link to="#">{product.title}</Link></h4>
                                                      </td>
                                                      <td className="product-price">₹{product.price}</td>
                                                      <td className="product-quantity">
                                                        <div className="cart--plus--minus">
                                                          <form action="#" className="num-block">
                                                            <input
                                                              type="text"
                                                              className="in-num"
                                                              value={cart.quantity}
                                                              readonly=""
                                                            />
                                                            <div className="qtybutton-box">
                                                              <span className="plus">
                                                                <i className="fas fa-angle-up"></i>
                                                              </span>
                                                              <span className="minus dis">
                                                                <i className="fas fa-angle-down"></i>
                                                              </span>
                                                            </div>
                                                          </form>
                                                        </div>
                                                      </td>
                                                      <td className="product-subtotal">
                                                        <span>₹{product.price}</span>
                                                      </td>
                                                      <td className="product-delete">
                                                        <i className="far fa-trash-alt" onClick={() => { deletecart(cart.id);}}></i>
                                                      </td>
                                                    </tr>
                                                  )
                                                )}
                                              </tbody>
                                            })
                                        }
                                    </table>
                                </div>
                            </div>
                            <div className="shop-cart-bottom">
                                <div className="cart-coupon">
                                    <form action="#">
                                        <input type="text" placeholder="Enter Coupon Code..." />
                                        <button className="btn">Apply Coupon</button>
                                    </form>
                                </div>
                                <div className="continue-shopping">
                                    <Link to="/category" className="btn">Update Cart</Link>
                                </div>
                            </div>
                        </div>
                        <div className="col-xl-5 col-lg-12">
                            <div className='filter'>
                                <CheckBox handledelivery={deli => handledelivery(deli, 'category')} />
                            </div>
                            <div className="shop-cart-total">
                                <h3 className="title">Cart Totals</h3>
                                <div className="shop-cart-widget">
                                    <form action="#">
                                        <ul>
                                            <li className="sub-total"><span>Subtotal</span>₹{Total}</li>
                                            <li>
                                                <span>Shipping</span>
                                                <div className="shop-check-wrap">
                                                    <div className="custom-control custom-checkbox">
                                                        <input type="checkbox" className="custom-control-input"
                                                            id="customCheck1" />
                                                        <label className="custom-control-label" htmlFor="customCheck1">Free
                                                            Shipping</label>
                                                    </div>
                                                    <div className="custom-control custom-checkbox">
                                                        <input type="checkbox" className="custom-control-input"
                                                            id="customCheck2" />
                                                        <label className="custom-control-label" htmlFor="customCheck2">LOCAL PICKUP:
                                                            ₹69.00</label>
                                                    </div>
                                                </div>
                                            </li>
                                            <li className="cart-total-amount"><span>Total Price</span> <span className="amount">₹
                                            {Total + 69}</span></li>
                                        </ul>
                                        <Link to="#" className="btn">PROCEED TO CHECKOUT</Link>
                                    </form>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <Footer />
        </>
    )
}
